<style lang="scss">
	.facilities {
		display: flex;
		gap: 15px;

		> div {
			position: relative;

			&:hover .tooltip {
				transform: scale(1) translateX(-50%);
			}

			.tooltip {
				position: absolute;
				top: calc(100% + 5px);
				left: 50%;
				font-size: 12px;
				text-wrap: nowrap;

				padding: 7px 15px;
				border-radius: 10em;
				color: #fff;
				background: #27232780;

				transition: transform var(--transition-duration);
				transform: scale(0) translateX(-50%);
				transform-origin: left;
			}
		}
	}
</style>
